class BayesianWinRate:
    def __init__(self, prior_wins=4, prior_losses=6):
        self.alpha = prior_wins  # pseudocounts
        self.beta = prior_losses

    def update(self, win):
        if win:
            self.alpha += 1
        else:
            self.beta += 1

    def get_win_rate(self):
        return self.alpha / (self.alpha + self.beta)

# Your 40% win rate strategy
belief = BayesianWinRate(4, 6)
print(f'Prior win rate: {belief.get_win_rate():.1%}')

# Simulate 5 trades: W, L, W, W, L
for outcome in [True, False, True, True, False]:
    belief.update(outcome)
    print(f'Updated win rate: {belief.get_win_rate():.1%}')
# After 5 trades (3W, 2L): 7/15 ≈ 46.7%
